INSERT INTO `about_us` (`id`, `description`, `created_at`) VALUES
(2, '<h2><strong>About us</strong></h2><h4><strong>PEC Education Consultants offers free consultancy, guidance as well as assistance to curious students who are interested to study abroad for their Bachelor’s and Master’s studies. It is a pioneer inspiration behind the success of student’s destined universities. Moreover, we serve without any service charge for Universities in Canada &amp; the USA. Sometimes, we offer a full or partial discount for the University application fee. We also assist students for the Universities of&nbsp; Australia, UK, &nbsp;New Zealand, Sweden, Germany, Norway, Finland, Netherlands, and many more universities of the different parts of the world.</strong></h4><p>&nbsp;</p><p><strong>We have already provided a huge amount of students for overseas admission. In addition, we have 93% visa success rate. We also specialize in designing and implementing test courses, training and linguistic programs and seminars throughout the country and exchanges PTE Academic, IELTS, and Spoken English program.&nbsp; PEC Education Consultant’s offices and training centers are located in Mirpur 10 and Uttara in Dhaka. Moreover, we serve online PTE &amp; IELTS courses for distant indoor and outdoor students.</strong></p><p><img src=\"https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?fit=1024%2C683&amp;ssl=1\" alt=\"\" srcset=\"https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?w=2560&amp;ssl=1 2560w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=1024%2C683&amp;ssl=1 1024w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=1536%2C1024&amp;ssl=1 1536w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=2048%2C1365&amp;ssl=1 2048w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=270%2C180&amp;ssl=1 270w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?resize=600%2C400&amp;ssl=1 600w, https://i0.wp.com/pecpte.com/wp-content/uploads/2020/02/O6NM390-scaled.jpg?w=2340&amp;ssl=1 2340w\" sizes=\"100vw\" width=\"1024\"></p>', '2026-03-23 10:40:17');

