INSERT INTO `faq` (`id`, `question`, `answer`, `created_at`) VALUES
(2, 'What is PTE Academy test?', 'PTE Academic is the world’s leading computer-based test of English for study abroad and immigration purposes. It is approved by the Australian government for all visa applications and accepted by thousands of institutions in the UK, Australia, USA, Canada, New Zealand and Ireland, including Harvard, Yale and INSEAD. You can register for the test online or by phone. These scores are valid for a period of 2 years.', '2026-03-23 10:47:11'),
(3, 'What is PTE Academy test?', 'PTE Academic is the world’s leading computer-based test of English for study abroad and immigration purposes. It is approved by the Australian government for all visa applications and accepted by thousands of institutions in the UK, Australia, USA, Canada, New Zealand and Ireland, including Harvard, Yale and INSEAD. You can register for the test online or by phone. These scores are valid for a period of 2 years.', '2026-03-23 10:47:16'),
(4, 'What is PTE Academy test?', 'PTE Academic is the world’s leading computer-based test of English for study abroad and immigration purposes. It is approved by the Australian government for all visa applications and accepted by thousands of institutions in the UK, Australia, USA, Canada, New Zealand and Ireland, including Harvard, Yale and INSEAD. You can register for the test online or by phone. These scores are valid for a period of 2 years.', '2026-03-23 10:47:20');

